<template>
  <div class="guide-page" v-loading="loading">
    <el-row :gutter="30">
      <!-- 左侧图片与信息 -->
      <el-col :span="8">
        <el-card class="guide-image-card" shadow="hover">
          <img :src="style.imageUrl || 'https://via.placeholder.com/400x400?text=无图'" class="main-image" />
          <div class="image-caption">
            <h2>{{ style.name }}</h2>
            <p>{{ style.culturalMeaning || '文化寓意暂无' }}</p>
          </div>
        </el-card>
      </el-col>

      <!-- 右侧步骤与操作 -->
      <el-col :span="16">
        <el-tabs v-model="activeTab" class="guide-tabs">
          <el-tab-pane label="传统六步" name="traditional">
            <el-steps direction="vertical" :active="traditionalActive" finish-status="success" class="custom-steps">
              <el-step
                v-for="(step, index) in traditionalSteps"
                :key="index"
                :title="step.name"
                :description="step.description"
              />
            </el-steps>
          </el-tab-pane>
          <el-tab-pane label="疗愈简化版" name="simple">
            <el-steps direction="vertical" :active="simpleActive" finish-status="success" class="custom-steps">
              <el-step
                v-for="(step, index) in simpleSteps"
                :key="index"
                :title="step.name"
                :description="step.description"
              />
            </el-steps>
          </el-tab-pane>
        </el-tabs>

        <!-- 操作按钮区域 -->
        <div class="action-area">
          <!-- 未开始体验时显示开始按钮 -->
          <el-button
            v-if="!experiencing"
            type="primary"
            size="large"
            @click="startExperience"
            class="action-btn"
          >
            开始体验
          </el-button>

          <!-- 体验中显示上一步/下一步按钮 -->
          <div v-else class="step-controls">
            <el-button
              type="default"
              size="large"
              :disabled="currentActive === 0"
              @click="prevStep"
              class="step-btn"
            >
              上一步
            </el-button>
            <el-button
              type="primary"
              size="large"
              @click="nextStep"
              class="step-btn"
              :class="{ 'is-finish': isLastStep }"
            >
              {{ isLastStep ? '完成体验' : '下一步' }}
            </el-button>
          </div>
        </div>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import request from '@/utils/request'

export default {
  name: 'TheGuide',
  data() {
    return {
      id: this.$route.params.id,
      style: {},
      loading: false,
      activeTab: 'traditional', // 当前选中的标签页
      traditionalActive: 0,     // 传统步骤当前进度（0 表示未开始）
      simpleActive: 0,          // 简化步骤当前进度
      experiencing: false       // 是否正在体验中
    }
  },
  computed: {
    traditionalSteps() {
      return this.parseSteps(this.style.stepsTraditional)
    },
    simpleSteps() {
      return this.parseSteps(this.style.stepsSimple)
    },
    // 当前激活的步骤进度
    currentActive: {
      get() {
        return this.activeTab === 'traditional' ? this.traditionalActive : this.simpleActive
      },
      set(value) {
        if (this.activeTab === 'traditional') {
          this.traditionalActive = value
        } else {
          this.simpleActive = value
        }
      }
    },
    // 当前激活的步骤总数
    currentTotalSteps() {
      return this.activeTab === 'traditional' ? this.traditionalSteps.length : this.simpleSteps.length
    },
    // 是否是最后一步
    isLastStep() {
      return this.currentActive === this.currentTotalSteps
    }
  },
  created() {
    this.fetchDetail()
  },
  methods: {
    // 解析步骤 JSON，转换为对象数组
    parseSteps(stepsJson) {
      if (!stepsJson) return []
      try {
        const steps = JSON.parse(stepsJson)
        if (Array.isArray(steps)) {
          return steps.map(step => {
            if (typeof step === 'string') {
              return { name: step, description: '' }
            }
            return step
          })
        }
        return []
      } catch (e) {
        console.error('步骤解析失败', e)
        return []
      }
    },
    fetchDetail() {
      this.loading = true
      request.get(`/styles/${this.id}`)
        .then(res => {
          this.style = res
        })
        .catch(err => {
          console.error('获取详情失败', err)
          this.$message.error('获取详情失败')
        })
        .finally(() => {
          this.loading = false
        })
    },
    startExperience() {
      // 重置当前标签页进度为0
      this.currentActive = 0
      this.experiencing = true
    },
    nextStep() {
      if (this.currentActive < this.currentTotalSteps) {
        this.currentActive++
      }
      if (this.currentActive === this.currentTotalSteps) {
        // 完成所有步骤
        this.finishExperience()
      }
    },
    prevStep() {
      if (this.currentActive > 0) {
        this.currentActive--
      }
    },
    finishExperience() {
      this.experiencing = false
      this.$message.success('体验完成！')
    }
  }
}
</script>

<style scoped>
.guide-page {
  max-width: 1200px;
  margin: 0 auto;
  padding: 30px;
}
.guide-image-card {
  border: none;
  background: transparent;
  box-shadow: none;
}
.main-image {
  width: 100%;
  border-radius: 16px;
  box-shadow: var(--card-shadow);
  border: 2px solid var(--gold);
  padding: 4px;
  background: white;
  transition: transform 0.3s;
}
.main-image:hover {
  transform: scale(1.02);
}
.image-caption {
  margin-top: 20px;
  text-align: center;
}
.image-caption h2 {
  color: var(--primary-blue);
  font-size: 1.8rem;
  margin-bottom: 8px;
}
.image-caption p {
  color: #555;
  font-style: italic;
  line-height: 1.6;
}
.guide-tabs {
  background: white;
  border-radius: 16px;
  padding: 20px;
  box-shadow: var(--card-shadow);
}
.custom-steps ::v-deep(.el-step__head.is-success) {
  color: var(--gold);
  border-color: var(--gold);
}
.custom-steps ::v-deep(.el-step__title.is-success) {
  color: var(--primary-blue);
  font-weight: bold;
}
.custom-steps ::v-deep(.el-step__description) {
  color: #666;
  font-size: 0.95rem;
}
.action-area {
  margin-top: 30px;
  text-align: center;
}
.action-btn {
  background: linear-gradient(135deg, var(--primary-blue), #2a4a9e);
  border: 1px solid var(--gold);
  padding: 12px 40px;
  font-size: 1.2rem;
  border-radius: 30px;
  box-shadow: 0 4px 12px rgba(30, 58, 138, 0.3);
  transition: all 0.3s;
}
.action-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 16px rgba(30, 58, 138, 0.4);
}
.step-controls {
  display: flex;
  justify-content: center;
  gap: 20px;
}
.step-btn {
  min-width: 120px;
  padding: 10px 24px;
  font-size: 1.1rem;
  border-radius: 30px;
  transition: all 0.3s;
}
.step-btn.is-finish {
  background: linear-gradient(135deg, var(--gold), #e5b73b);
  border-color: var(--primary-blue);
  color: var(--primary-blue);
  font-weight: bold;
}
.step-btn.is-finish:hover {
  transform: scale(1.05);
  box-shadow: 0 4px 12px rgba(212, 175, 55, 0.4);
}
.el-button[disabled] {
  opacity: 0.6;
  cursor: not-allowed;
}
</style>