<template>
  <div class="select-page">
    <h1 class="page-title">珐琅样式馆</h1>
    <!-- 筛选栏 -->
    <el-card class="filter-bar" shadow="never">
      <el-form :inline="true" :model="filters">
        <el-form-item label="大类">
          <el-select v-model="filters.typeCategory" placeholder="全部" clearable>
            <el-option label="器型" value="器型" />
            <el-option label="纹饰" value="纹饰" />
            <el-option label="色彩" value="色彩" />
            <el-option label="时代风格" value="时代风格" />
          </el-select>
        </el-form-item>
        <el-form-item label="疗愈目标">
          <el-input v-model="filters.healingGoal" placeholder="输入关键词" clearable />
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="handleSearch">查询</el-button>
          <el-button @click="resetFilters">重置</el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <!-- 卡片列表 -->
    <el-row :gutter="20">
      <el-col :xs="12" :sm="8" :md="6" v-for="item in styleList" :key="item.id">
        <el-card class="style-card" :body-style="{ padding: '0' }" shadow="hover">
          <div class="style-img">
            <img :src="item.imageUrl || 'https://via.placeholder.com/300x200?text=无图'" />
            <!-- 收藏按钮 -->
            <div class="favorite-btn" @click.stop="toggleFavorite(item)">
              <span class="star">{{ isFavorite(item.id) ? '★' : '☆' }}</span>
            </div>
          </div>
          <div class="style-info">
            <h3>{{ item.name }}</h3>
            <p class="style-desc">{{ item.description || '暂无描述' }}</p>
            <div class="style-footer">
              <el-tag size="small" v-if="item.typeCategory">{{ item.typeCategory }}</el-tag>
              <el-button type="text" @click="goToGuide(item.id)">查看操作</el-button>
            </div>
          </div>
        </el-card>
      </el-col>
    </el-row>

    <!-- 分页 -->
    <el-pagination
      @current-change="handlePageChange"
      @size-change="handleSizeChange"
      :current-page="pagination.current"
      :page-sizes="[12, 24, 36]"
      :page-size="pagination.size"
      layout="total, sizes, prev, pager, next, jumper"
      :total="pagination.total"
      class="pagination"
    />
  </div>
</template>

<script>
import request from '@/utils/request'
import favorite from '@/utils/favorite'  // 默认导入
const { getFavorites, addFavorite, removeFavorite, isFavorite } = favorite

export default {
  name: 'TheSelect',
  data() {
    return {
      filters: {
        typeCategory: '',
        healingGoal: ''
      },
      styleList: [],
      pagination: {
        current: 1,
        size: 12,
        total: 0
      },
      favorites: []
    }
  },
  created() {
    this.favorites = getFavorites()
    this.fetchData()
  },
  methods: {
    fetchData() {
      const params = {
        page: this.pagination.current,
        size: this.pagination.size,
        ...this.filters
      }
      request.get('/styles', { params }).then(res => {
        this.styleList = res.records
        this.pagination.total = res.total
        this.pagination.current = res.current
        this.pagination.size = res.size
      }).catch(err => {
        console.error('获取数据失败', err)
      })
    },
    handleSearch() {
      this.pagination.current = 1
      this.fetchData()
    },
    resetFilters() {
      this.filters.typeCategory = ''
      this.filters.healingGoal = ''
      this.handleSearch()
    },
    handlePageChange(page) {
      this.pagination.current = page
      this.fetchData()
    },
    handleSizeChange(size) {
      this.pagination.size = size
      this.handlePageChange(1)
    },
    goToGuide(id) {
      this.$router.push(`/guide/${id}`)
    },
    toggleFavorite(item) {
      if (isFavorite(item.id)) {
        removeFavorite(item.id)
        this.$message.success('已取消收藏')
      } else {
        addFavorite(item)
        this.$message.success('收藏成功')
      }
      this.favorites = getFavorites()
    },
    isFavorite(id) {
      return isFavorite(id)
    }
  }
}
</script>

<style scoped>
.select-page {
  max-width: 1400px;
  margin: 0 auto;
  padding: 20px;
}
.page-title {
  font-size: 2.5rem;
  color: var(--primary-blue);
  text-align: center;
  margin-bottom: 30px;
  position: relative;
}
.page-title::before,
.page-title::after {
  content: '❧';
  color: var(--gold);
  font-size: 2rem;
  margin: 0 20px;
  opacity: 0.6;
}
.filter-bar {
  margin-bottom: 30px;
  background: rgba(255, 255, 255, 0.8);
  backdrop-filter: blur(8px);
  border: 1px solid rgba(212, 175, 55, 0.2);
}
.style-card {
  margin-bottom: 20px;
  border: 1px solid transparent;
  transition: all 0.3s;
  overflow: hidden;
  border-radius: 12px;
}
.style-card:hover {
  border-color: var(--gold);
  box-shadow: var(--hover-shadow);
}
.style-img {
  height: 180px;
  overflow: hidden;
  position: relative;
}
.style-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.5s;
}
.style-card:hover .style-img img {
  transform: scale(1.1);
}
.favorite-btn {
  position: absolute;
  top: 10px;
  right: 10px;
  background: rgba(255,255,255,0.8);
  border-radius: 50%;
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-size: 20px;
  color: var(--gold);
  transition: all 0.2s;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}
.favorite-btn:hover {
  transform: scale(1.1);
  background: white;
}
.star {
  line-height: 1;
}
.style-info {
  padding: 16px;
}
.style-info h3 {
  font-size: 1.2rem;
  color: var(--primary-blue);
  margin-bottom: 8px;
}
.style-desc {
  color: #666;
  font-size: 0.9rem;
  line-height: 1.5;
  height: 2.7rem;
  overflow: hidden;
  text-overflow: ellipsis;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
}
.style-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 12px;
}
.pagination {
  margin-top: 30px;
  text-align: right;
}
</style>