<script>
import styles from '@/mock/styles' // 引入样式数据

export default {
  name: 'TheHome',
  data() {
    return {
      randomStyle: {} // 存储随机选中的样式
    }
  },
  created() {
    this.getRandomStyle()
  },
  methods: {
    // 从样式列表中随机选取一个
    getRandomStyle() {
      if (styles && styles.length > 0) {
        const randomIndex = Math.floor(Math.random() * styles.length)
        this.randomStyle = styles[randomIndex]
      } else {
        // 保底数据（防止 mock 数据未加载）
        this.randomStyle = {
          id: 1,
          name: '缠枝莲纹',
          imageUrl: 'https://via.placeholder.com/400x400?text=缠枝莲纹',
          description: '经典的缠枝莲纹样，寓意生生不息。'
        }
      }
    },
    // 跳转到对应指南页
    goToRandomGuide() {
      if (this.randomStyle.id) {
        this.$router.push(`/guide/${this.randomStyle.id}`)
      }
    }
  }
}
</script>

