<template>
  <div class="chat-page">
    <el-row :gutter="20">
      <el-col :span="16">
        <div class="chat-window" ref="chatWindow">
          <div v-for="(msg, index) in messages" :key="index" :class="['message', msg.role]">
            <div class="avatar" :class="msg.role">
              {{ msg.role === 'ai' ? '🤖' : '👤' }}
            </div>
            <div class="bubble">{{ msg.content }}</div>
          </div>
        </div>
        <div class="input-area">
          <el-input
            v-model="userInput"
            type="textarea"
            :rows="2"
            placeholder="描述您的情绪或困扰..."
            @keyup.enter="sendMessage"
          />
          <el-button type="primary" @click="sendMessage" :loading="sending">发送</el-button>
        </div>
      </el-col>
      <el-col :span="8">
        <div class="recommend-panel" v-if="recommendations.length">
          <h3>疗愈推荐</h3>
          <el-card v-for="item in recommendations" :key="item.id" class="recommend-card" shadow="hover">
            <div class="recommend-img">
              <img :src="item.imageUrl" :alt="item.name" />
            </div>
            <h4>{{ item.name }}</h4>
            <p>{{ item.reason }}</p>
            <el-button type="text" @click="goToGuide(item.id)">查看操作 ></el-button>
          </el-card>
        </div>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import request from '@/utils/request' // 根据您的项目结构调整路径

export default {
  name: 'AIChat',
  data() {
    return {
      userInput: '',
      messages: [
        { role: 'ai', content: '你好，我是您的疗愈助手。请告诉我您最近的情绪状态或困扰，我会为您推荐适合的掐丝珐琅样式。' }
      ],
      sending: false,
      recommendations: []
    }
  },
  methods: {
    sendMessage() {
      if (!this.userInput.trim()) return
      this.messages.push({ role: 'user', content: this.userInput })
      this.sending = true

      request.post('/chat', { message: this.userInput })
        .then(res => {
          // 添加 AI 回复
          this.messages.push({ role: 'ai', content: res.reply })

          // 转换推荐样式数据，适配前端展示
          this.recommendations = res.recommendedStyles.map(item => ({
            id: item.id,
            name: item.name,
            imageUrl: item.imageUrl || 'https://via.placeholder.com/300x200?text=无图',
            reason: item.description || item.healingSymbol || '暂无描述'
          }))

          this.userInput = ''
        })
        .catch(err => {
          console.error('聊天接口调用失败', err)
          this.messages.push({ role: 'ai', content: '抱歉，服务暂时不可用，请稍后再试。' })
        })
        .finally(() => {
          this.sending = false
          this.$nextTick(() => {
            this.scrollToBottom()
          })
        })
    },
    scrollToBottom() {
      const chatWindow = this.$refs.chatWindow
      if (chatWindow) {
        chatWindow.scrollTop = chatWindow.scrollHeight
      }
    },
    goToGuide(id) {
      this.$router.push(`/guide/${id}`)
    }
  }
}
</script>

<style scoped>
.chat-page {
  max-width: 1400px;
  margin: 0 auto;
  padding: 20px;
}
.chat-window {
  height: 500px;
  overflow-y: auto;
  padding: 20px;
  background: #fff;
  border-radius: 16px;
  box-shadow: var(--card-shadow);
  margin-bottom: 20px;
}
.message {
  display: flex;
  margin-bottom: 20px;
  animation: fadeIn 0.3s;
}
.message.ai {
  flex-direction: row;
}
.message.user {
  flex-direction: row-reverse;
}
.avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  margin: 0 12px;
  background: #f0f0f0;
  border: 2px solid var(--gold);
}
.avatar.user {
  background: var(--primary-blue);
  color: white;
  border-color: var(--gold);
}
.bubble {
  max-width: 70%;
  padding: 12px 18px;
  border-radius: 18px;
  background: #f0f0f0;
  position: relative;
  word-wrap: break-word;
}
.message.ai .bubble {
  background: #e8f0fe;
  border-bottom-left-radius: 4px;
}
.message.user .bubble {
  background: var(--primary-blue);
  color: white;
  border-bottom-right-radius: 4px;
}
.input-area {
  display: flex;
  gap: 12px;
  align-items: flex-end;
}
.input-area .el-textarea {
  flex: 1;
}
.recommend-panel {
  background: white;
  border-radius: 16px;
  padding: 20px;
  box-shadow: var(--card-shadow);
}
.recommend-panel h3 {
  color: var(--primary-blue);
  margin-bottom: 20px;
  text-align: center;
  position: relative;
}
.recommend-panel h3::after {
  content: '';
  display: block;
  width: 50px;
  height: 2px;
  background: var(--gold);
  margin: 8px auto 0;
}
.recommend-card {
  margin-bottom: 20px;
  border: 1px solid rgba(212, 175, 55, 0.2);
  border-radius: 12px;
  overflow: hidden;
}
.recommend-img {
  height: 120px;
  overflow: hidden;
}
.recommend-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s;
}
.recommend-card:hover .recommend-img img {
  transform: scale(1.05);
}
.recommend-card h4 {
  margin: 12px 12px 6px;
  color: var(--primary-blue);
}
.recommend-card p {
  margin: 0 12px 12px;
  color: #666;
  font-size: 0.9rem;
} 
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}
</style>