// src/utils/favorite.js
const STORAGE_KEY = 'favorite_styles'

function getFavorites() {
  const stored = localStorage.getItem(STORAGE_KEY)
  return stored ? JSON.parse(stored) : []
}

function addFavorite(style) {
  const list = getFavorites()
  if (!list.some(item => item.id === style.id)) {
    list.push(style)
    localStorage.setItem(STORAGE_KEY, JSON.stringify(list))
  }
}

function removeFavorite(styleId) {
  const list = getFavorites()
  const newList = list.filter(item => item.id !== styleId)
  localStorage.setItem(STORAGE_KEY, JSON.stringify(newList))
}

function isFavorite(styleId) {
  return getFavorites().some(item => item.id === styleId)
}

// 添加调试输出（可在控制台查看是否加载）
console.log('✅ favorite.js loaded (default export)', { getFavorites, addFavorite, removeFavorite, isFavorite })

export default {
  getFavorites,
  addFavorite,
  removeFavorite,
  isFavorite
}