import { createRouter, createWebHistory } from 'vue-router'
import TheHome from '@/components/TheHome.vue'        // 注意变量名与文件名对应
import AIChat from '@/components/AIChat.vue'
import TheSelect from '@/components/TheSelect.vue'
import TheGuide from '@/components/TheGuide.vue'

const routes = [
  { path: '/', name: 'TheHome', component: TheHome },      // 使用 TheHome 变量
  { path: '/ai-chat', name: 'AIChat', component: AIChat },
  { path: '/select', name: 'TheSelect', component: TheSelect },
  { path: '/guide/:id', name: 'TheGuide', component: TheGuide, props: true }
]

const router = createRouter({
  history: createWebHistory(),
  routes
})

export default router