// src/utils/request.js
import mockStyles from '@/mock/styles'

import { getChatReply, getRecommendations, analyzeChat } from '@/mock/chat'
// 检查 Mock 数据是否加载成功
console.log('【Mock】styles:', mockStyles)
console.log('【Mock】chat functions:', { getChatReply, getRecommendations })

// 如果 Mock 数据加载失败，使用备用空数据
const safeMockStyles = Array.isArray(mockStyles) ? mockStyles : []

const request = {
  // 模拟 GET 请求
  get(url, config) {
    console.log('【Request GET】', url, config)
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        try {
          if (url.startsWith('/styles')) {
            if (url.includes('/styles/')) {
              // 获取单个样式详情
              const id = url.split('/').pop()
              console.log('【Detail】id:', id)
              const style = safeMockStyles.find(s => s.id === Number(id) || s.id === id)
              if (style) {
                console.log('【Detail】found:', style)
                resolve(style)
              } else {
                console.error('【Detail】not found, use default')
                // 返回一个默认样式，避免页面空白
                resolve({
                  id: Number(id) || 1,
                  name: '默认样式',
                  imageUrl: 'https://via.placeholder.com/400x400?text=暂无图片',
                  culturalMeaning: '暂无文化寓意',
                  stepsTraditional: '[]',
                  stepsSimple: '[]'
                })
              }
            } else {
              // 样式列表
              const { page = 1, size = 12, typeCategory, healingGoal } = config?.params || {}
              console.log('【List】params:', { page, size, typeCategory, healingGoal })
              let filtered = [...safeMockStyles]

              if (typeCategory) {
                filtered = filtered.filter(s => s.typeCategory === typeCategory)
              }
              if (healingGoal) {
                filtered = filtered.filter(s => s.healingGoal?.includes(healingGoal))
              }

              const total = filtered.length
              const records = filtered.slice((page - 1) * size, page * size)

              console.log('【List】total:', total, 'records:', records.length)
              resolve({
                records,
                total,
                current: Number(page),
                size: Number(size)
              })
            }
          } else {
            console.error('【GET】unknown url:', url)
            reject(new Error('未模拟的 GET 请求: ' + url))
          }
        } catch (err) {
          console.error('【GET】error:', err)
          // 返回空数据，避免页面崩溃
          if (url.includes('/styles/')) {
            resolve({ id: 1, name: '默认', stepsTraditional: '[]', stepsSimple: '[]' })
          } else {
            resolve({ records: [], total: 0, current: 1, size: 12 })
          }
        }
      }, 300)
    })
  },

  // 模拟 POST 请求
  post(url, data) {
    console.log('【Request POST】', url, data)
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        try {
          if (url === '/analyze') {
  const { messages } = data
  // 调用分析函数
  const { analysis, recommendedStyles } = analyzeChat(messages) // 需要导入 analyzeChat
  resolve({ analysis, recommendedStyles })
}
          if (url === '/chat') {
            const message = data.message || ''
            console.log('【Chat】message:', message)
            const reply = getChatReply(message)
            const recommendedStyles = getRecommendations(message)
            console.log('【Chat】reply:', reply, 'recommendations:', recommendedStyles)
            resolve({ reply, recommendedStyles })
          } else {
            console.error('【POST】unknown url:', url)
            reject(new Error('未模拟的 POST 请求: ' + url))
          }
        } catch (err) {
          console.error('【POST】error:', err)
          // 返回默认回复
          resolve({
            reply: '感谢您的分享，我为您推荐以下样式。',
            recommendedStyles: safeMockStyles.slice(0, 2).map(s => ({
              id: s.id,
              name: s.name,
              imageUrl: s.imageUrl,
              description: s.description,
              healingSymbol: s.culturalMeaning
            }))
          })
        }
      }, 500)
    })
  }
}

export default request