// 默认回复（当没有任何关键词匹配时）
const defaultReply = '感谢您的分享。我为您推荐几款经典的掐丝珐琅样式，希望能带来平静与疗愈。'
const defaultIds = [1, 2, 3]

// 匹配函数：返回匹配的 emotionMap 项，若无则返回 null
function matchEmotion(message) {
  const lowerMsg = message.toLowerCase()
  for (let item of emotionMap) {
    // 检查是否包含任意关键词
    if (item.keywords.some(keyword => lowerMsg.includes(keyword))) {
      return item
    }
  }
  return null
}

// 根据消息返回回复
export function getChatReply(message) {
  const matched = matchEmotion(message)
  return matched ? matched.reply : defaultReply
}

// 根据消息返回推荐样式列表
export function getRecommendations(message) {
  const matched = matchEmotion(message)
  const ids = matched ? matched.recommendIds : defaultIds
  const safeStyles = Array.isArray(styles) ? styles : []
  return safeStyles
    .filter(s => ids.includes(s.id))
    .map(s => ({
      id: s.id,
      name: s.name,
      imageUrl: s.imageUrl,
      description: s.description,
      healingSymbol: s.culturalMeaning,
      reason: s.description || s.culturalMeaning
    }))
}

// 综合分析多条用户消息（用于分析按钮）
export function analyzeChat(messages) {
  const combinedText = messages.join(' ').toLowerCase()
  
  let bestScore = 0
  let bestMatch = null
  for (let item of emotionMap) {
    let score = 0
    for (let keyword of item.keywords) {
      const regex = new RegExp(keyword, 'g')
      const matches = combinedText.match(regex)
      if (matches) score += matches.length
    }
    if (score > bestScore) {
      bestScore = score
      bestMatch = item
    }
  }
  
  if (!bestMatch) {
    bestMatch = { reply: defaultReply, recommendIds: defaultIds }
  }
  
  const safeStyles = Array.isArray(styles) ? styles : []
  const recommendedStyles = safeStyles
    .filter(s => bestMatch.recommendIds.includes(s.id))
    .map(s => ({
      id: s.id,
      name: s.name,
      imageUrl: s.imageUrl,
      description: s.description,
      healingSymbol: s.culturalMeaning,
      reason: s.description || s.culturalMeaning
    }))
  
  return {
    analysis: bestMatch.reply,
    recommendedStyles
  }
}